INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxew00a6mavtgvcyp35s', 'cmp8dtxeq009mmavtdrwsucg2', 'cmp8dtxbf000cmavt5aq9r3xj', 'చాలా బాగుంది సర్! రోడ్లు బాగుపడితే ట్రాఫిక్ సమస్య తీరుతుంది 👏', '2026-05-16T13:28:49.257Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxex00a8mavtune8lu0j', 'cmp8dtxeq009mmavtdrwsucg2', 'cmp8dtxbc0006mavt3bpkbux9', 'మా షాపు ముందు రోడ్ చాలా చెడుగా ఉంది. దయచేసి త్వరగా పనులు మొదలుపెట్టండి 🙏', '2026-05-16T13:28:49.257Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxex00aamavt0vb3kn9l', 'cmp8dtxeq009mmavtdrwsucg2', 'cmp8dtxbj000kmavtk2a6wkka', 'అవును! మేము త్వరలో పనులు ప్రారంభిస్తాము. మీ సహకారానికి ధన్యవాదాలు! 🙏', '2026-05-16T13:28:49.258Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxey00acmavtnhgi5xhk', 'cmp8dtxet009wmavt4b1t2rc9', 'cmp8dtxbf000cmavt5aq9r3xj', 'నిజమే! ఆ దోశ సూపర్! 🤤 నేను కూడా వారానికి రెండుసార్లు వెళ్తాను!', '2026-05-16T13:28:49.258Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxey00aemavtlvem29oa', 'cmp8dtxet009wmavt4b1t2rc9', 'cmp8dtxbe000amavtmxdzjyu5', 'కిరణ్ గారు, మీ ఫుడ్ రివ్యూస్ చాలా బాగుంటాయి! 👏😊', '2026-05-16T13:28:49.259Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxey00agmavt259vduia', 'cmp8dtxeu00a0mavtx0j2ijk3', 'cmp8dtxbk000mmavtg6adh05f', 'మార్కెట్ ధరలు షేర్ చేయడం చాలా మంచిది! థాంక్స్ ప్రియా! 🙌', '2026-05-16T13:28:49.259Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxez00aimavt7hxloy8j', 'cmp8dtxew00a4mavtk5p58hrn', 'cmp8dtxbf000cmavt5aq9r3xj', 'పెసరట్టు + కాఫీ కాంబో సూపర్! నేను ఈ వారం ట్రై చేశాను ☕😋', '2026-05-16T13:28:49.259Z'::timestamp) ON CONFLICT DO NOTHING;
INSERT INTO public."Comment" ("id", "postId", "userId", "content", "createdAt") VALUES ('cmp8dtxf000akmavt1x80sygc', 'cmp8dtxeq009omavtv2z1d6yx', 'cmp8dtxbd0008mavt96zjmdxl', 'డిజిటల్ క్లాస్‌రూమ్ చాలా అవసరం. ధన్యవాదాలు సర్! 👏', '2026-05-16T13:28:49.260Z'::timestamp) ON CONFLICT DO NOTHING;